import { Routes, Route } from "react-router-dom";

import LoginPage from "./components/Logi";
import VerifyOtp from "./components/VerifyOtp";
import Admin from "./components/Admin";
import SignUp from "./components/SignUp";

function App() {
  return (
    <Routes>

      <Route
        path="/"
        element={<LoginPage />}
      />

      <Route
        path="/verify-otp"
        element={<VerifyOtp />}
      />

      <Route
        path="/admin"
        element={<Admin />}
      />

      <Route
        path="/create-user"
        element={<SignUp />}
      />

    </Routes>
  );
}

export default App;
